#!/usr/bin/env python3

import requests
import json
from typing import List, Dict

class IADocumentationIngester:
    def __init__(self, om_url: str, token: str):
        self.om_url = om_url
        self.headers = {
            'Authorization': f'Bearer {token}',
            'Content-Type': 'application/json'
        }

    def get_or_create_drive_service(self, service_config: Dict) -> str:
        '''Create Drive Service if not exists, return service ID'''
        endpoint = f'{self.om_url}/api/v1/services/driveServices'

        response = requests.post(
            endpoint,
            headers=self.headers,
            json=service_config
        )

        if response.status_code == 201:
            return response.json()['id']
        elif response.status_code == 409:
            # Service exists, fetch it
            list_endpoint = f'{self.om_url}/api/v1/services/driveServices?name={service_config["name"]}'
            list_response = requests.get(list_endpoint, headers=self.headers)
            return list_response.json()['data'][0]['id']
        else:
            raise Exception(f'Failed to create service: {response.text}')

    def create_file_entity(self, file_config: Dict) -> str:
        '''Create a File entity, return file ID'''
        endpoint = f'{self.om_url}/api/v1/entities/files'

        response = requests.post(
            endpoint,
            headers=self.headers,
            json=file_config
        )

        if response.status_code == 201:
            return response.json()['id']
        else:
            raise Exception(f'Failed to create file: {response.text}')

    def ingest_documentation(self, drive_service_config: Dict, files_list: List[Dict]):
        '''Main ingestion method'''
        # Create or get Drive Service
        service_id = self.get_or_create_drive_service(drive_service_config)
        print(f'Using Drive Service: {service_id}')

        # Create File entities
        created_files = []
        for file_config in files_list:
            file_config['service'] = {
                'id': service_id,
                'type': 'driveService'
            }

            try:
                file_id = self.create_file_entity(file_config)
                created_files.append(file_id)
                print(f'✓ Created file: {file_config["displayName"]}')
            except Exception as e:
                print(f'✗ Failed to create file {file_config["displayName"]}: {e}')

        return created_files

